31	void Opencore::CreateCorePrStatus(int pid) {
32	    if (!threads.size()) return;
33	
34	    prstatus.assign(threads.size(), {});
35	    int prnum = (int)prstatus.size();
36	
37	    int cur = 1;
38	    for (int index = 0; index < prnum; index++) {
39	        pid_t tid = threads[index].pid;
40	        int idx;
41	        if (tid == getTid()) {
42	            idx = 0;
43	            prstatus[idx].pr_pid = tid;
44	            // top thread maybe use ucontext prs
45	            if (getContext()) {
46	                struct ucontext *context = (struct ucontext *) getContext();
47	                x86_64::pt_regs uc_regs;
48	                memset(&uc_regs, 0x0, sizeof(x86_64::pt_regs));
49	                uc_regs.r15 = context->uc_mcontext.gregs[7];
50	                uc_regs.r14 = context->uc_mcontext.gregs[6];
51	                uc_regs.r13 = context->uc_mcontext.gregs[5];
52	                uc_regs.r12 = context->uc_mcontext.gregs[4];
53	                uc_regs.rbp = context->uc_mcontext.gregs[10];
54	                uc_regs.rbx = context->uc_mcontext.gregs[11];
55	                uc_regs.r11 = context->uc_mcontext.gregs[3];
56	                uc_regs.r10 = context->uc_mcontext.gregs[2];
57	                uc_regs.r9 = context->uc_mcontext.gregs[1];
58	                uc_regs.r8 = context->uc_mcontext.gregs[0];
59	                uc_regs.rax = context->uc_mcontext.gregs[13];
60	                uc_regs.rcx = context->uc_mcontext.gregs[14];
61	                uc_regs.rdx = context->uc_mcontext.gregs[12];
62	                uc_regs.rsi = context->uc_mcontext.gregs[9];
63	                uc_regs.rdi = context->uc_mcontext.gregs[8];
64	                uc_regs.rip = context->uc_mcontext.gregs[16];
65	                uc_regs.cs = context->uc_mcontext.gregs[18];
66	                uc_regs.flags = context->uc_mcontext.gregs[17];
67	                uc_regs.rsp = context->uc_mcontext.gregs[15];
68	                uc_regs.ss = context->uc_mcontext.gregs[21];
69	                uc_regs.fs = context->uc_mcontext.gregs[20];
70	                uc_regs.gs = context->uc_mcontext.gregs[19];
71	                memcpy(&prstatus[idx].pr_reg, &uc_regs, sizeof(x86_64::pt_regs));
72	                continue;
73	            }
74	        } else {
75	            // 0 top thread was truncated
76	            idx = (cur >= prnum) ? 0 : cur;
77	            ++cur;
78	            prstatus[idx].pr_pid = tid;
79	        }
80	
81	        struct iovec ioVec = {
82	            &prstatus[idx].pr_reg,
83	            sizeof(x86_64::pt_regs),
84	        };
85	
86	        if (ptrace(PTRACE_GETREGSET, tid, NT_PRSTATUS, &ioVec) < 0)
87	            continue;
88	    }
89	
90	    extra_note_filesz += (sizeof(Elf64_prstatus) + sizeof(Elf64_Nhdr) + 8) * prnum;
91	    extra_note_filesz += sizeof(siginfo_t) + sizeof(Elf64_Nhdr) + 8;      // NT_SIGINFO
92	}
