94	void Opencore::WriteCorePrStatus(FILE* fp) {
95	    Elf64_Nhdr elf_nhdr;
96	    elf_nhdr.n_namesz = NOTE_CORE_NAME_SZ;
97	    elf_nhdr.n_descsz = sizeof(Elf64_prstatus);
98	    elf_nhdr.n_type = NT_PRSTATUS;
99	
100	    char magic[8];
101	    memset(magic, 0, sizeof(magic));
102	    snprintf(magic, NOTE_CORE_NAME_SZ, ELFCOREMAGIC);
103	
104	    int prnum = (int)prstatus.size();
105	    for (int index = 0; index < prnum; index++) {
106	        fwrite(&elf_nhdr, sizeof(Elf64_Nhdr), 1, fp);
107	        fwrite(magic, sizeof(magic), 1, fp);
108	        fwrite(&prstatus[index], sizeof(Elf64_prstatus), 1, fp);
109	        if (!index) WriteCoreSignalInfo(fp);
110	    }
111	}
